unitsize(0.5 cm);

pair C, P, Q;

C = (2,3);
P = (-1,-1);
Q = interp(C,P,3);
draw((-10,0)--(10,0));
draw((0,-10)--(0,10));
draw(C--Q,dashed);

dot("$2 + 3i$", (2,3), NE);
dot("$-1 - i$", (-1,-1), NW);
dot("$-7 - 9i$", (-7,-9), SW);
[/asy]

